var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>작전 중 부상자 다수 발생! 다행히 사망자는 없습니다!</color>","JPN":"<color=#ffd34c>作戦中に負傷者多数発生！　幸い死亡者はいません！</color>","ENG":"<color=#ffd34c>We've got multiple casualties! But fortunately no K.I.A.s!</color>","TWN":"<color=#ffd34c>作戰中有多人受傷！幸好沒有人死亡！</color>"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>본부, 수배자에게는 전차포가 통하지 않습니다! 더 강한 화력이 필요합니다!</color>","JPN":"<color=#ffd34c>本部、指名手配犯には戦車砲が効きません！　より強い火力が必要です！</color>","ENG":"<color=#ffd34c>HQ, the anti-tank rounds have no effect on the suspect! Requesting more firepower!</color>","TWN":"<color=#ffd34c>總部，裝甲砲對通緝犯無效！需要更強的火力！</color>"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시를 쑥대밭으로 만들 생각이냐?! 허가할 수 없다!</color>","JPN":"<color=#ffd34c>都市をめちゃくちゃにするにするつもりか！？　許可できない！</color>","ENG":"<color=#ffd34c>Are you trying to raze the entire city?! Request denied!</color>","TWN":"<color=#ffd34c>你是想毀掉城市嗎？！我絕不允許！</color>"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>악천후 탓에 공중지원도 어렵습니다! 부탁드립니다!</color>","JPN":"<color=#ffd34c>悪天候のせいで空中からの支援も厳しいです！　お願いします！</color>","ENG":"<color=#ffd34c>We can't call in air support either due to inclement weather! Please, sir!</color>","TWN":"<color=#ffd34c>由於氣候不佳，也無法進行空中支援，Over！</color>"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"적대 개체 반응이 감지되지 않습니다.","JPN":"敵性個体反応が感知されません。","ENG":"Hostility no longer detected.","TWN":"未感應到敵對個體反應。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"잔여 동력은……. 현재 8.27퍼센트.","JPN":"残余エネルギーは……現在8.27％。","ENG":"Current remaining power is… 8.27%.","TWN":"剩餘動能…還有8.27%。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"빈번한 역장 생성이 동력 소비의 주요인이군요.","JPN":"頻繁なフォースシールドの生成がエネルギー消費の主要因ですね。","ENG":"The frequent generation of stasis fields appears to be most significant cause for the power drain.","TWN":"頻繁產生力場應該就是動能耗損的主因。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"CPU가 연산 부하를 견디지 못할 수 있습니다. 불필요한 교전은 되도록이면…….","JPN":"CPUが演算負荷に耐えられない可能性があります。不要な交戦はなるべく……","ENG":"The CPU may be unable to withstand the computational overload. I should avoid any unnecessary engagements…","TWN":"CPU無法承受運算負載壓力，盡可能避免不必要的衝突……"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"추돌사고 발생. 시가전용 장갑차량.","JPN":"追突事故発生。市街戦用装甲車。","ENG":"Crash detected. Caused by Armored Vehicle for Urban Warfare.","TWN":"發生追撞事件，是巷戰裝甲戰車。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"태스크포스 <color=#ffd34c>블랙 타이드</color>의 식별신호 감지.","JPN":"タスクフォースカンパニー<color=#ffd34c>ブラックタイド</color>の識別信号を感知。","ENG":"TASKFORCE <color=#ffd34c>Black Tide</color> call sign detected.","TWN":"感應到是特遣勢力<color=#ffd34c>黑潮</color>的識別信號。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……피할 계획이었습니다만. 이건 어렵겠군요.","JPN":"……避けるつもりでしたが。これは難しいですね。","ENG":"…So much for avoiding engagements. This one seems inevitable.","TWN":"……原本是想能免則免的，看來可能有困難。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우와, 먼저 들이받았는데 채리엇이 찌그러졌네요.","JPN":"わあ、突っ込んだのはこっちなのに、チャリオットがぺちゃんこになりましたね。","ENG":"Wow, we're the ones who crashed into her, but the Chariot's all crumpled up.","TWN":"哇，我先撞上去後步戰車就凹咧？！"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경찰차였으면 사망진단서 떼었어야겠는데요.","JPN":"パトカーだったら私たちの死亡診断書案件です。","ENG":"We'd be long gone if we tried this in our regular patrol car.","TWN":"如果是警車可能要開死亡證明。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"오우, 가슴 벌렁벌렁한 드라이브였어!","JPN":"おう、体がゾクゾクするドライブだったぜ！","ENG":"Dang, what a rush!","TWN":"哇喔～真是痛快的兜風！"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"덕분에 눈 깜짝할 새 도착했군요! 협조 감사합니다!","JPN":"おかげさまであっという間に着きましたね！　ご協力ありがとうございます！","ENG":"But you got us here in a blink! Thanks for the help!","TWN":"多虧了你，一眨眼就到了呢！多謝你的協助！"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};